		function SendToServer()
{       
	GetProxy().StoreService().SetUserStore("SDP_IDsCVs", array2stringcustom(arrB, "ROWS", "ROW"));
	return true;
}

function internal_load()
{
	if(Ctrl('listlegajos'))
	{
	  if(Ctrl('listlegajos').GetXValue()!= '')
	  {
	  	if(!SetListLegajos())
	  		return false;
	  }
	}
  var auxArr;
	auxArr = exec_qry();
	if (auxArr==null) return;

	arrB = auxArr; 
	remove(arrB, arrA);	
	refreshList("list2", arrB);
}
function internal_filter()
{
	if(Ctrl('listlegajos'))
	{
	  if(Ctrl('listlegajos').GetXValue()!= '')
	  {
	  	if(!SetListLegajos())
	  		return false;  	
	  }
	}
  var auxArr;
	auxArr = exec_qry();
