function internal_loadadd()
{ 
	if(Ctrl('listlegajos'))
	{
	  if(Ctrl('listlegajos').GetXValue()!= '')
	  {
	  	if(!SetListLegajos())
	  		return false;  	
	  }
	}
  var auxArr;
	auxArr = exec_qry();
	if (auxArr==null) return;  

	remove(auxArr, arrA);		
