	refreshList("list2", arrB);
}

function internal_find()
{
	if(Ctrl('listlegajos'))
	{
	  if(Ctrl('listlegajos').GetXValue()!= '')
	  {
	  	if(!SetListLegajos())
	  		return false;  	
	  }
	}
  var auxArr;
  var key;
	auxArr = exec_qry();
	if (auxArr==null) return;  

	intersect(auxArr, arrB);
	key="";
	for (key in auxArr) break;
	if (key!="") 
		Ctrl("list2").SetXValue(key.substr(1));
	else
		alert("No se encontro ningun registro.");
}


function Filtrar()
{   
	if(Ctrl("aviso1").GetXValue() == "")
	{
		alert("Debe indicar el Aviso para realizar la Postulación");
		return false;
	}

	if (!confirm('Los CVs seleccionados serán postulados en el aviso. Está seguro que desea continuar?'))
		return false;

	if(Ctrl('l_mail'))
		if(Ctrl('l_mail').GetXValue() == "1") { 
			if (!confirm('Se va a enviar un correo electrónico a todos los CVs postulados. Está seguro que desea continuar?'))
				return false;
		}		

	SendToServer();
	Ctrl("main").DoEvent("ACCEPT");
}          

function SetTipoAviso(obj)
{
	var oi_aviso, nSQL, objAviso;
	oi_aviso = obj.GetXValue();
	if(oi_aviso != '')
	{
		nSQL = GetProxy().SQLService();
  		objAviso = nSQL.GetOBJ(Ctrl("main").getResource("tipo_aviso"), "<PARAM oi_aviso=\""+oi_aviso+"\" />");
  		Ctrl('tipoAviso').SetXValue(objAviso.tipo_aviso);
	}
	else
		Ctrl('tipoAviso').SetXValue('');
	return true;
}
